#include <stdio.h>
#include <stdlib.h>

int* calculateSpan(int* prices, int n) {
    int* span = (int*)malloc(n * sizeof(int));
    int* stack = (int*)malloc(n * sizeof(int));
    int top = -1;
    for (int i = 0; i < n; ++i) {
        while (top != -1 && prices[stack[top]] <= prices[i]) {
            --top;
        }
        span[i] = (top == -1) ? i + 1 : i - stack[top];
        stack[++top] = i;
    }
    free(stack);
    return span;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n; scanf("%d", &n);
        int* prices = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; ++i) scanf("%d", &prices[i]);
        int* span = calculateSpan(prices, n);
        for (int i = 0; i < n; ++i) {
            printf("%d", span[i]);
            if (i + 1 < n) printf(" ");
        }
        printf("\n");
        free(prices);
        free(span);
    }
    return 0;
}

